// node_conv_216 - pointwise (1x1) conv2d under the tiled-streaming contract.
// IC=64, OC=256, IH=IW=56, OH=OW=56, MP=4, channel_tile=32.
// IN_BEATS=2, OUT_BEATS=8. Latency = IN_BEATS + OC_PASSES*(MP*K_TOTAL+6) = 16770.
module node_conv_216 (
    input  wire              clk,
    input  wire              rst_n,
    input  wire              valid_in,
    output reg               ready_in,
    input  wire [255:0]      data_in,
    output reg               valid_out,
    output reg  [255:0]      data_out
);
    localparam integer IC            = 64;
    localparam integer OC            = 256;
    localparam integer KH            = 1;
    localparam integer KW            = 1;
    localparam integer K_TOTAL       = 64;
    localparam integer MP            = 4;
    localparam integer OC_PASSES     = 64;
    localparam integer CHANNEL_TILE  = 32;
    localparam integer IN_BEATS      = 2;
    localparam integer OUT_BEATS     = 8;
    localparam integer TILE_BITS     = 256;
    localparam integer IC_BITS       = 512;
    localparam integer OC_BITS       = 2048;
    localparam integer NUM_PIXELS    = 3136;

    localparam integer SCALE_MULT    = 4953;
    localparam integer SCALE_SHIFT   = 19;

    localparam integer PROD_W        = 16;
    localparam integer ACC_W         = 22;
    localparam integer BIASED_W      = 33;
    localparam integer SCALE_CONST_W = 14;
    localparam integer SCALED_W      = 47;

    localparam signed [SCALE_CONST_W-1:0] SCALE_MULT_CONST = SCALE_MULT;
    localparam signed [SCALED_W-1:0] SCALE_ROUND_HALF =
        {{(SCALED_W-1){1'b0}}, 1'b1} <<< (SCALE_SHIFT - 1);
    localparam signed [SCALED_W-1:0] SCALE_ROUND_HALF_M1 =
        SCALE_ROUND_HALF - {{(SCALED_W-1){1'b0}}, 1'b1};

    (* rom_style="block", ram_style="block" *) reg signed [7:0]  weights [0:OC*K_TOTAL-1];
    (* rom_style="block", ram_style="block" *) reg signed [31:0] biases  [0:OC-1];

    initial begin
        $readmemh("C:/Users/User/Desktop/RTL_LLM_CLAUDE/nn2rtl-repo/output/weights/node_conv_216_weights.hex", weights);
        $readmemh("C:/Users/User/Desktop/RTL_LLM_CLAUDE/nn2rtl-repo/output/weights/node_conv_216_bias.hex", biases);
    end

    localparam [2:0] ST_LOAD    = 3'd0;
    localparam [2:0] ST_COMPUTE = 3'd1;
    localparam [2:0] ST_DRAIN   = 3'd2;
    localparam [2:0] ST_BIAS    = 3'd3;
    localparam [2:0] ST_SCALE   = 3'd4;
    localparam [2:0] ST_OUTPUT  = 3'd5;
    localparam [2:0] ST_EMIT    = 3'd6;

    reg [2:0]  state;
    reg [1:0]  in_beat_idx;
    reg [3:0]  out_beat_idx;
    reg [6:0]  oc_group;
    reg [1:0]  lane_counter;
    reg [6:0]  k_counter;
    reg [1:0]  drain_counter;
    reg [12:0] active_emit_count;

    reg [IC_BITS-1:0] in_latch;

    reg signed [7:0]                          weight_q;
    reg signed [7:0]                          in_q1;
    (* use_dsp = "yes" *) reg signed [PROD_W-1:0] mul_q;
    reg [1:0]                                 lane_q1;
    reg [1:0]                                 lane_q2;
    reg                                       mac_v1;
    reg                                       mac_v2;

    reg signed [ACC_W-1:0]    acc0, acc1, acc2, acc3;
    reg signed [BIASED_W-1:0] biased0, biased1, biased2, biased3;
    reg signed [SCALED_W-1:0] scaled0, scaled1, scaled2, scaled3;
    reg signed [SCALED_W-1:0] v_tmp0, v_tmp1, v_tmp2, v_tmp3;

    reg [OC_BITS-1:0] out_pack;

    wire [15:0]       weight_addr_comb = (oc_group * MP + lane_counter) * K_TOTAL + k_counter;
    wire signed [7:0] in_byte_comb     = in_latch[k_counter*8 +: 8];
    wire              issue_active     = (state == ST_COMPUTE);
    wire [8:0]        global_oc_base   = oc_group * MP;

    always @(*) begin
        // [INVARIANT:ROUNDING]
        v_tmp0 = (scaled0 + (scaled0[SCALED_W-1] ? SCALE_ROUND_HALF_M1 : SCALE_ROUND_HALF)) >>> SCALE_SHIFT;
        v_tmp1 = (scaled1 + (scaled1[SCALED_W-1] ? SCALE_ROUND_HALF_M1 : SCALE_ROUND_HALF)) >>> SCALE_SHIFT;
        v_tmp2 = (scaled2 + (scaled2[SCALED_W-1] ? SCALE_ROUND_HALF_M1 : SCALE_ROUND_HALF)) >>> SCALE_SHIFT;
        v_tmp3 = (scaled3 + (scaled3[SCALED_W-1] ? SCALE_ROUND_HALF_M1 : SCALE_ROUND_HALF)) >>> SCALE_SHIFT;
    end

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            state             <= ST_LOAD;
            ready_in          <= 1'b1;
            valid_out         <= 1'b0;
            data_out          <= {256{1'b0}};
            in_beat_idx       <= 2'd0;
            out_beat_idx      <= 4'd0;
            oc_group          <= 7'd0;
            lane_counter      <= 2'd0;
            k_counter         <= 7'd0;
            drain_counter     <= 2'd0;
            active_emit_count <= 13'd0;
            in_latch          <= {IC_BITS{1'b0}};
            out_pack          <= {OC_BITS{1'b0}};
            weight_q          <= 8'sd0;
            in_q1             <= 8'sd0;
            mul_q             <= {PROD_W{1'b0}};
            lane_q1           <= 2'd0;
            lane_q2           <= 2'd0;
            mac_v1            <= 1'b0;
            mac_v2            <= 1'b0;
            acc0              <= {ACC_W{1'b0}};
            acc1              <= {ACC_W{1'b0}};
            acc2              <= {ACC_W{1'b0}};
            acc3              <= {ACC_W{1'b0}};
            biased0           <= {BIASED_W{1'b0}};
            biased1           <= {BIASED_W{1'b0}};
            biased2           <= {BIASED_W{1'b0}};
            biased3           <= {BIASED_W{1'b0}};
            scaled0           <= {SCALED_W{1'b0}};
            scaled1           <= {SCALED_W{1'b0}};
            scaled2           <= {SCALED_W{1'b0}};
            scaled3           <= {SCALED_W{1'b0}};
        end else begin
            weight_q <= weights[weight_addr_comb];
            in_q1    <= in_byte_comb;
            lane_q1  <= lane_counter;
            mac_v1   <= issue_active;
            mul_q    <= weight_q * in_q1;
            lane_q2  <= lane_q1;
            mac_v2   <= mac_v1;

            if (mac_v2) begin
                case (lane_q2)
                    2'd0: acc0 <= acc0 + mul_q;
                    2'd1: acc1 <= acc1 + mul_q;
                    2'd2: acc2 <= acc2 + mul_q;
                    2'd3: acc3 <= acc3 + mul_q;
                endcase
            end

            case (state)
                ST_LOAD: begin
                    if (valid_in && ready_in) begin
                        in_latch[in_beat_idx*TILE_BITS +: TILE_BITS] <= data_in;
                        if (in_beat_idx == IN_BEATS-1) begin
                            in_beat_idx  <= 2'd0;
                            ready_in     <= 1'b0;
                            state        <= ST_COMPUTE;
                            oc_group     <= 7'd0;
                            lane_counter <= 2'd0;
                            k_counter    <= 7'd0;
                            acc0 <= {ACC_W{1'b0}};
                            acc1 <= {ACC_W{1'b0}};
                            acc2 <= {ACC_W{1'b0}};
                            acc3 <= {ACC_W{1'b0}};
                        end else begin
                            in_beat_idx <= in_beat_idx + 2'd1;
                        end
                    end
                end

                ST_COMPUTE: begin
                    if (k_counter == K_TOTAL-1) begin
                        k_counter <= 7'd0;
                        if (lane_counter == MP-1) begin
                            lane_counter  <= 2'd0;
                            state         <= ST_DRAIN;
                            drain_counter <= 2'd0;
                        end else begin
                            lane_counter <= lane_counter + 2'd1;
                        end
                    end else begin
                        k_counter <= k_counter + 7'd1;
                    end
                end

                ST_DRAIN: begin
                    if (drain_counter == 2'd2) begin
                        state <= ST_BIAS;
                    end else begin
                        drain_counter <= drain_counter + 2'd1;
                    end
                end

                ST_BIAS: begin
                    biased0 <= $signed(acc0) + $signed(biases[global_oc_base]);
                    biased1 <= $signed(acc1) + $signed(biases[global_oc_base + 9'd1]);
                    biased2 <= $signed(acc2) + $signed(biases[global_oc_base + 9'd2]);
                    biased3 <= $signed(acc3) + $signed(biases[global_oc_base + 9'd3]);
                    state   <= ST_SCALE;
                end

                ST_SCALE: begin
                    scaled0 <= $signed(biased0) * $signed(SCALE_MULT_CONST);
                    scaled1 <= $signed(biased1) * $signed(SCALE_MULT_CONST);
                    scaled2 <= $signed(biased2) * $signed(SCALE_MULT_CONST);
                    scaled3 <= $signed(biased3) * $signed(SCALE_MULT_CONST);
                    state   <= ST_OUTPUT;
                end

                ST_OUTPUT: begin
                    out_pack[(global_oc_base + 9'd0)*8 +: 8] <= (v_tmp0 >  47'sd127) ?  8'sd127 : (v_tmp0 < -47'sd128) ? -8'sd128 : v_tmp0[7:0];
                    out_pack[(global_oc_base + 9'd1)*8 +: 8] <= (v_tmp1 >  47'sd127) ?  8'sd127 : (v_tmp1 < -47'sd128) ? -8'sd128 : v_tmp1[7:0];
                    out_pack[(global_oc_base + 9'd2)*8 +: 8] <= (v_tmp2 >  47'sd127) ?  8'sd127 : (v_tmp2 < -47'sd128) ? -8'sd128 : v_tmp2[7:0];
                    out_pack[(global_oc_base + 9'd3)*8 +: 8] <= (v_tmp3 >  47'sd127) ?  8'sd127 : (v_tmp3 < -47'sd128) ? -8'sd128 : v_tmp3[7:0];

                    if (oc_group == OC_PASSES-1) begin
                        valid_out    <= 1'b1;
                        data_out     <= out_pack[0 +: TILE_BITS];
                        out_beat_idx <= 4'd1;
                        state        <= ST_EMIT;
                    end else begin
                        oc_group <= oc_group + 7'd1;
                        state    <= ST_COMPUTE;
                        acc0 <= {ACC_W{1'b0}};
                        acc1 <= {ACC_W{1'b0}};
                        acc2 <= {ACC_W{1'b0}};
                        acc3 <= {ACC_W{1'b0}};
                    end
                end

                ST_EMIT: begin
                    if (out_beat_idx == OUT_BEATS) begin
                        valid_out    <= 1'b0;
                        state        <= ST_LOAD;
                        ready_in     <= 1'b1;
                        out_beat_idx <= 4'd0;
                        oc_group     <= 7'd0;
                        if (active_emit_count == NUM_PIXELS - 1) begin
                            active_emit_count <= 13'd0;
                        end else begin
                            active_emit_count <= active_emit_count + 13'd1;
                        end
                    end else begin
                        data_out     <= out_pack[out_beat_idx*TILE_BITS +: TILE_BITS];
                        out_beat_idx <= out_beat_idx + 4'd1;
                        valid_out    <= 1'b1;
                    end
                end

                default: state <= ST_LOAD;
            endcase
        end
    end

endmodule
